import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface PriorityMessage {
  sender: string;
  subject: string;
  receivedAt: string;
}

interface EmailData {
  unreadCount: number;
  priorityMessages: PriorityMessage[];
  dailyVolumeTrend: number[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const emailData = response.data as EmailData;
  const metaData = response.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#F8FAFC' }}>
              Mail Manager
            </Typography>
            <Typography variant="body1" sx={{ color: metaData.primaryColor }}>
              Unread Emails: {emailData.unreadCount}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8', mb: 1 }}>
              Priority Messages
            </Typography>
            <Stack spacing={1}>
              {emailData.priorityMessages.map((message, index) => (
                <Box key={index} sx={{ bgcolor: '#111827', p: 1.5, borderRadius: 1 }}>
                  <Typography variant="body2" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
                    {message.sender}
                  </Typography>
                  <Typography variant="caption" sx={{ color: '#6B7280' }}>
                    {message.subject}
                  </Typography>
                  <Typography variant="caption" sx={{ color: '#6B7280', display: 'block' }}>
                    {message.receivedAt}
                  </Typography>
                </Box>
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: emailData.dailyVolumeTrend,
                  color: metaData.primaryColor,
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  data: emailData.dailyVolumeTrend.map((_, index) => index + 1),
                  scaleType: 'linear',
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'volume', min: 0 }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="volume"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
